-- =============================================================================
-- 002 — Full menu seed (production density)
-- Safe to re-run: replaces menu_items only (reservations untouched).
-- Catalog = 16 dishes × 3 copies = 48 rows (duplicates OK for grid density).
-- =============================================================================

truncate table public.menu_items restart identity;


notify pgrst, 'reload schema';

select count(*) as menu_items from public.menu_items;
